#!/usr/bin/env node
// PreToolUse(Edit|Write|MultiEdit): block edits to generated proxy code.
// Files under AutoGeneratedCode/ are produced by Editor/DevTools/AudioProxyModifierCodeGenerator.cs.
const fs = require('fs');
let data;
try { data = JSON.parse(fs.readFileSync(0, 'utf8')); } catch { process.exit(0); }
const fp = data && data.tool_input && data.tool_input.file_path;
if (!fp) process.exit(0);
const norm = fp.replace(/\\/g, '/');

if (/\/Runtime\/Player\/AutoGeneratedCode\//.test(norm)) {
  process.stderr.write(`Blocked: '${fp}' is auto-generated. Edit the generator (Assets/BroAudio/Editor/DevTools/AudioProxyModifierCodeGenerator.cs) and regenerate via the BroAudio Dev Tools window instead.\n`);
  process.exit(2);
}
process.exit(0);
